 1	import React, { FC } from 'react';
 2	
 3	import LoadingEmptyState from '@kubevirt-utils/components/LoadingEmptyState/LoadingEmptyState';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Button, EmptyState, EmptyStateBody, EmptyStateFooter } from '@patternfly/react-core';
 6	
 7	import { CustomConnectComponentProps } from './utils/VncConsoleTypes';
 8	
 9	const VncConnect: FC<CustomConnectComponentProps> = ({ connect, isConnecting }) => {
10	  const { t } = useKubevirtTranslation();
11	  return (
12	    <>
13	      {!isConnecting && (
14	        <EmptyState>
15	          <EmptyStateBody>{t('Click Connect to open the VNC console.')}</EmptyStateBody>
16	          <EmptyStateFooter>
17	            <Button onClick={connect} variant="primary">
18	              {t('Connect')}
19	            </Button>
20	          </EmptyStateFooter>
21	        </EmptyState>
22	      )}
23	      {isConnecting && <LoadingEmptyState bodyContents={t('Connecting')} />})
24	    </>
25	  );
26	};
27	
28	export default VncConnect;

